(1, 'System Dealer', 'system', 'superadmin@gmail.com', '+923280287524', NULL, NULL, NULL, NULL, NULL, 45, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '#ffffff', '#c0392b', NULL, NULL, 1, '2026-04-02 12:10:29', '2026-04-02 12:10:29', NULL),
(2, 'Dealer 1', 'dealer-1', 'irfanulhaq6312@gmail.com', '+923280287525', 'webgurus365.com', 'webgurus365.com', 'Angel Motors Inc', 'USA', 'support@gmail.com', 60, NULL, 'The payment estimator is not an advertisement or offer for specific terms of credit and actual terms may vary. Payment amounts presented are for illustrative purposes only and may not be available. Not all models are available in all states. Actual vehicle price may vary by Dealer. The Estimated Monthly Payment amount calculated is based on the variables entered, the price of the vehicle you entered, the term you select, the down payment you enter, the Annual Percentage Rate (APR) you select, and any net trade-in amount. The payment estimate displayed does not include taxes, title, license and/or registration fees. Payment amount is for illustrative purposes only. Actual prices may vary by Dealer. Payment amounts may be different due to various factors such as fees, specials, rebates, term, down payment, APR, net trade-in, and applicable tax rate. Actual APR is based on available finance programs and the creditworthiness of the customer. Not all customers will qualify for credit or for the lowest rate. Please contact an authorized dealer for actual rates, program details and actual terms.', 'It is the customer\'s sole responsibility to verify the existence and condition of any equipment listed. Neither the dealership nor Webgurus365 is responsible for misprints on prices or equipment. It is the customer\'s sole responsibility to verify the accuracy of the prices with the dealer, including the pricing for all added accessories. Financing Fees apply for all vehicles not purchased with cash. See Dealer for details.', 'By clicking the Securely Send Deposit button I authorize Angel Motors Inc to charge the amount listed above to the credit card provided herein, as a non-refundable down payment, with the intent to purchase. I agree to pay for this purchase in accordance with the issuing bank cardholder agreement. I understand that I waive all my rights to dispute this transaction with the issuing bank cardholder. Please DO NOT complete this credit card authorization form if you are not committed to purchasing the vehicle. Feel free to contact us with any questions prior to completing this form.*', NULL, NULL, 'Test Announcement', 'Test Announcement Hover', '#000000', '#c0392b', 1, 7, 1, '2026-04-02 12:10:30', '2026-04-08 20:44:59', NULL);

